transform_js:
const seriesMap = {};
rawData.rows.forEach(r => {
  if (!seriesMap[r.category]) seriesMap[r.category] = [];
  // echarts の data は配列形式で渡すのが一般的 [x, y, size, name]
  seriesMap[r.category].push([r.x_value, r.y_value, r.size_value, r.name]);
});
const seriesInfo = Object.keys(seriesMap).map(cat => {
    return {
       name: cat,
       type: 'scatter',
       data: seriesMap[cat],
       // サイズの値（人口など）は巨大すぎるので、平方根などで調整して見た目のバランスを取る
       symbolSize: function(data) { return Math.max(Math.sqrt(data[2]) * 2, 10); },
       itemStyle: {
           opacity: 0.8
       }
    };
});
transformedData = seriesInfo;

echarts_js:
option = {
  title: {
    text: 'Wealth, Health, and Population',
    subtext: 'Bubble Chart',
    left: '5%'
  },
  legend: {
    right: '10%',
    top: '3%',
    data: transformedData.map(s => s.name)
  },
  tooltip: {
    trigger: 'item',
    formatter: function (param) {
        // param.data: [x, y, size, name]
        return param.data[3] + '<br/>' +
               'GDP: ' + param.data[0] + '<br/>' +
               'Life Expectancy: ' + param.data[1] + '<br/>' +
               'Population (M): ' + param.data[2];
    }
  },
  grid: {
    left: '8%',
    right: '8%',
    top: '18%',
    bottom: '10%',
    containLabel: true
  },
  xAxis: {
    type: 'log',
    name: 'GDP per capita',
    splitLine: { show: false },
    axisLabel: { formatter: '${value}' }
  },
  yAxis: {
    type: 'value',
    name: 'Life Expectancy',
    splitLine: { show: true, lineStyle: { type: 'dashed' } },
    scale: true
  },
  series: transformedData
};
